/**
 * GET /api/admin/qr-pdf
 *
 * Generates an A4 PDF with a 3×5 grid of QR codes — one per table.
 * Each QR encodes http://SHOP_IP:SHOP_PORT/order?table=N.
 * Protected by admin cookie auth.
 */

import { NextRequest } from "next/server";
import path from "path";
import PDFDocument from "pdfkit";
import QRCode from "qrcode";

import { checkAdminCookie } from "@/lib/auth";

// Force Node.js runtime — pdfkit uses Buffer/fs internally
export const runtime = "nodejs";

export async function GET(request: NextRequest) {
  // ── Auth gate ──────────────────────────────────────────────
  const cookieHeader = request.headers.get("cookie");
  if (!checkAdminCookie(cookieHeader)) {
    return Response.json({ error: "Unauthorized" }, { status: 401 });
  }

  // ── Env var validation ─────────────────────────────────────
  const shopIp = process.env.SHOP_IP;
  if (!shopIp) {
    return Response.json(
      { error: "SHOP_IP chưa được cấu hình" },
      { status: 400 },
    );
  }
  const shopPort = process.env.SHOP_PORT || "3000";
  const tableCount = Math.max(0, parseInt(process.env.TABLE_COUNT || "15", 10));

  if (tableCount === 0) {
    return Response.json(
      { error: "TABLE_COUNT phải lớn hơn 0" },
      { status: 400 },
    );
  }

  // ── Font validation ────────────────────────────────────────
  const fontPath = path.join(process.cwd(), "public", "fonts", "Inter.ttf");
  try {
    const fs = await import("fs");
    if (!fs.existsSync(fontPath)) {
      return Response.json(
        { error: "Font file not found" },
        { status: 500 },
      );
    }
  } catch {
    return Response.json(
      { error: "Font file not found" },
      { status: 500 },
    );
  }

  try {
    // ── Generate QR buffers ────────────────────────────────────
    const qrBuffers: Buffer[] = [];
    for (let n = 1; n <= tableCount; n++) {
      const url = `http://${shopIp}:${shopPort}/order?table=${n}`;
      const buf = await QRCode.toBuffer(url, {
        width: 300,
        errorCorrectionLevel: "M",
      });
      qrBuffers.push(buf);
    }

    // ── Build PDF ──────────────────────────────────────────────
    // A4: 595.28 × 841.89 pt, margin 40
    const doc = new PDFDocument({ size: "A4", margin: 40 });
    doc.registerFont("Vietnamese", fontPath);

    // Collect PDF chunks (cannot pipe to Response in Next.js)
    const chunks: Buffer[] = [];
    doc.on("data", (chunk: Buffer) => chunks.push(chunk));
    const pdfReady = new Promise<void>((resolve, reject) => {
      doc.on("end", resolve);
      doc.on("error", reject);
    });

    // ── Layout constants ─────────────────────────────────────
    const pageWidth = 595.28;
    const margin = 40;
    const cols = 3;
    const rows = 5;
    const perPage = cols * rows;
    const availableWidth = pageWidth - margin * 2;
    const colWidth = availableWidth / cols;
    const qrSize = 120;
    const rowHeight = 150;
    const titleHeight = 50;

    // ── Render pages ─────────────────────────────────────────
    const totalPages = Math.ceil(tableCount / perPage);

    for (let page = 0; page < totalPages; page++) {
      if (page > 0) doc.addPage();

      // Page title (only first page gets big title)
      if (page === 0) {
        doc
          .font("Vietnamese")
          .fontSize(20)
          .fillColor("#000000")
          .text("QR Code - TraSua", margin, margin, {
            align: "center",
            width: availableWidth,
          });
      }

      const startY = page === 0 ? margin + titleHeight : margin;
      const startIdx = page * perPage;
      const endIdx = Math.min(startIdx + perPage, tableCount);

      for (let i = startIdx; i < endIdx; i++) {
        const localIdx = i - startIdx;
        const col = localIdx % cols;
        const row = Math.floor(localIdx / cols);

        const cellX = margin + col * colWidth;
        const cellY = startY + row * rowHeight;

        // Center QR in column
        const qrX = cellX + (colWidth - qrSize) / 2;

        // Embed QR image
        doc.image(qrBuffers[i], qrX, cellY, {
          width: qrSize,
          height: qrSize,
        });

        // "Bàn N" label — 14pt, centered below QR
        doc
          .font("Vietnamese")
          .fontSize(14)
          .fillColor("#1a1a1a")
          .text(`Bàn ${i + 1}`, cellX, cellY + qrSize + 4, {
            width: colWidth,
            align: "center",
          });

        // "Quét để đặt món" subtitle — 10pt, lighter
        doc
          .font("Vietnamese")
          .fontSize(10)
          .fillColor("#666666")
          .text("Quét để đặt món", cellX, cellY + qrSize + 20, {
            width: colWidth,
            align: "center",
          });
      }
    }

    doc.end();
    await pdfReady;

    const pdfBuffer = Buffer.concat(chunks);

    return new Response(pdfBuffer, {
      status: 200,
      headers: {
        "Content-Type": "application/pdf",
        "Content-Disposition": 'attachment; filename="trasua-qr-codes.pdf"',
        "Cache-Control": "no-store",
      },
    });
  } catch (err) {
    console.error("[qr-pdf] PDF generation failed:", err);
    return Response.json(
      { error: "PDF generation failed" },
      { status: 500 },
    );
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'

/**
 * GET /api/admin/tables
 *
 * Returns all tables ordered by number.
 * Each table includes orderCount: count of unpaid, non-cancelled orders.
 */
export async function GET() {
  try {
    const tables = await prisma.table.findMany({
      orderBy: { number: 'asc' },
      include: {
        orders: {
          where: {
            status: { notIn: ['PAID', 'CANCELLED'] },
          },
          select: { id: true },
        },
      },
    })

    const result = tables.map((t) => ({
      id: t.id,
      number: t.number,
      name: t.name,
      orderCount: t.orders.length,
    }))

    console.log(`[GET /api/admin/tables] Returning ${result.length} tables`)

    return NextResponse.json({ tables: result })
  } catch (error) {
    console.error('[GET /api/admin/tables] Failed:', error)
    return NextResponse.json(
      { error: 'Không thể tải danh sách bàn. Vui lòng thử lại.' },
      { status: 500 },
    )
  }
}

/**
 * POST /api/admin/tables
 *
 * Creates a new table.
 * Auto-numbers to max(existing number) + 1.
 * Name auto-generated as "Bàn N".
 */
export async function POST(_request: NextRequest) {
  try {
    // Get the highest existing table number
    const last = await prisma.table.findFirst({
      orderBy: { number: 'desc' },
      select: { number: true },
    })

    const nextNumber = last ? last.number + 1 : 1
    const name = `Bàn ${nextNumber}`

    const table = await prisma.table.create({
      data: { number: nextNumber, name },
    })

    console.log(`[POST /api/admin/tables] Created table #${table.id}: ${table.name} (number=${table.number})`)

    return NextResponse.json(
      {
        id: table.id,
        number: table.number,
        name: table.name,
        orderCount: 0,
      },
      { status: 201 },
    )
  } catch (error) {
    console.error('[POST /api/admin/tables] Failed:', error)
    return NextResponse.json(
      { error: 'Không thể tạo bàn mới. Vui lòng thử lại.' },
      { status: 500 },
    )
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'

type RouteContext = { params: Promise<{ id: string }> }

/**
 * GET /api/admin/tables/[id]
 *
 * Returns a single table with its unpaid order count.
 */
export async function GET(_request: NextRequest, context: RouteContext) {
  const { id: idStr } = await context.params
  const id = parseInt(idStr, 10)

  if (isNaN(id)) {
    return NextResponse.json({ error: 'ID bàn không hợp lệ.' }, { status: 400 })
  }

  try {
    const table = await prisma.table.findUnique({
      where: { id },
      include: {
        orders: {
          where: { status: { notIn: ['PAID', 'CANCELLED'] } },
          select: { id: true },
        },
      },
    })

    if (!table) {
      return NextResponse.json({ error: 'Bàn không tồn tại.' }, { status: 404 })
    }

    console.log(`[GET /api/admin/tables/${id}] Table: ${table.name}, orderCount=${table.orders.length}`)

    return NextResponse.json({
      id: table.id,
      number: table.number,
      name: table.name,
      orderCount: table.orders.length,
    })
  } catch (error) {
    console.error(`[GET /api/admin/tables/${id}] Failed:`, error)
    return NextResponse.json(
      { error: 'Không thể tải thông tin bàn. Vui lòng thử lại.' },
      { status: 500 },
    )
  }
}

/**
 * PUT /api/admin/tables/[id]
 *
 * Renames a table.
 * Body: { name: string }
 */
export async function PUT(request: NextRequest, context: RouteContext) {
  const { id: idStr } = await context.params
  const id = parseInt(idStr, 10)

  if (isNaN(id)) {
    return NextResponse.json({ error: 'ID bàn không hợp lệ.' }, { status: 400 })
  }

  let body: Record<string, unknown>
  try {
    body = await request.json()
  } catch {
    return NextResponse.json({ error: 'Dữ liệu không hợp lệ.' }, { status: 400 })
  }

  const { name } = body

  if (!name || typeof name !== 'string' || name.trim().length === 0) {
    return NextResponse.json({ error: 'Tên bàn không được để trống.' }, { status: 400 })
  }

  const trimmedName = name.trim()
  if (trimmedName.length > 50) {
    return NextResponse.json({ error: 'Tên bàn không được quá 50 ký tự.' }, { status: 400 })
  }

  try {
    const existing = await prisma.table.findUnique({ where: { id } })
    if (!existing) {
      return NextResponse.json({ error: 'Bàn không tồn tại.' }, { status: 404 })
    }

    const table = await prisma.table.update({
      where: { id },
      data: { name: trimmedName },
    })

    console.log(`[PUT /api/admin/tables/${id}] Renamed to: ${table.name}`)

    return NextResponse.json({
      id: table.id,
      number: table.number,
      name: table.name,
      orderCount: existing.orders?.length ?? 0,
    })
  } catch (error) {
    console.error(`[PUT /api/admin/tables/${id}] Failed:`, error)
    return NextResponse.json(
      { error: 'Không thể cập nhật bàn. Vui lòng thử lại.' },
      { status: 500 },
    )
  }
}

/**
 * DELETE /api/admin/tables/[id]
 *
 * Deletes a table only if it has no unpaid orders.
 * Guard: checks for orders with status NOT IN ['PAID', 'CANCELLED'].
 */
export async function DELETE(_request: NextRequest, context: RouteContext) {
  const { id: idStr } = await context.params
  const id = parseInt(idStr, 10)

  if (isNaN(id)) {
    return NextResponse.json({ error: 'ID bàn không hợp lệ.' }, { status: 400 })
  }

  try {
    const table = await prisma.table.findUnique({ where: { id } })
    if (!table) {
      return NextResponse.json({ error: 'Bàn không tồn tại.' }, { status: 404 })
    }

    // Deletion guard: check for unpaid orders
    const unpaidOrder = await prisma.order.findFirst({
      where: { tableId: id, status: { notIn: ['PAID', 'CANCELLED'] } },
    })

    if (unpaidOrder) {
      console.log(`[DELETE /api/admin/tables/${id}] Guard triggered: unpaid orders exist`)
      return NextResponse.json(
        { error: 'Bàn đang có đơn chưa thanh toán, không thể xoá.' },
        { status: 409 },
      )
    }

    await prisma.table.delete({ where: { id } })

    console.log(`[DELETE /api/admin/tables/${id}] Deleted table: ${table.name}`)

    return new NextResponse(null, { status: 204 })
  } catch (error) {
    console.error(`[DELETE /api/admin/tables/${id}] Failed:`, error)
    return NextResponse.json(
      { error: 'Không thể xoá bàn. Vui lòng thử lại.' },
      { status: 500 },
    )
  }
}

'use client'

import { usePathname } from 'next/navigation'
import Link from 'next/link'

// ─── Navigation Config ──────────────────────────────────────────────

const NAV_ITEMS = [
  { href: '/admin/menu', label: 'Thực đơn', emoji: '📋' },
  { href: '/admin/tables', label: 'Bàn', emoji: '🪑' },
  { href: '/admin/qr', label: 'QR Code', emoji: '📱' },
] as const

// ─── Admin Navigation ───────────────────────────────────────────────

export default function AdminNav() {
  const pathname = usePathname()

  return (
    <nav
      className="fixed bottom-0 left-0 right-0 z-50 bg-white/80 backdrop-blur-xl border-t border-amber-200/60 shadow-[0_-2px_16px_rgba(180,120,40,0.08)]"
      aria-label="Điều hướng quản trị"
    >
      <div className="max-w-7xl mx-auto flex items-stretch justify-around">
        {NAV_ITEMS.map(({ href, label, emoji }) => {
          const isActive = pathname.startsWith(href)

          return (
            <Link
              key={href}
              href={href}
              className={`
                relative flex flex-col items-center justify-center gap-1
                min-h-[56px] min-w-[72px] px-4 py-2
                text-xs font-semibold tracking-wide
                transition-all duration-200 ease-out
                ${
                  isActive
                    ? 'text-amber-900'
                    : 'text-amber-600/60 hover:text-amber-800 active:scale-95'
                }
              `}
              aria-current={isActive ? 'page' : undefined}
            >
              {/* Active indicator pill */}
              {isActive && (
                <span
                  className="absolute top-0 left-1/2 -translate-x-1/2 w-10 h-[3px] rounded-full bg-amber-500"
                  aria-hidden="true"
                />
              )}

              <span className="text-xl leading-none" aria-hidden="true">
                {emoji}
              </span>
              <span>{label}</span>
            </Link>
          )
        })}

        {/* Logout link */}
        <Link
          href="/admin/login"
          className="
            relative flex flex-col items-center justify-center gap-1
            min-h-[56px] min-w-[72px] px-4 py-2
            text-xs font-semibold tracking-wide
            text-amber-600/60 hover:text-red-600 active:scale-95
            transition-all duration-200 ease-out
          "
        >
          <span className="text-xl leading-none" aria-hidden="true">🚪</span>
          <span>Đăng xuất</span>
        </Link>
      </div>
    </nav>
  )
}

import { describe, it, expect, vi, beforeEach } from 'vitest'

// ─── Mock Prisma ────────────────────────────────────────────────────
const mockFindMany = vi.fn()
const mockFindFirst = vi.fn()
const mockCreate = vi.fn()
const mockFindUnique = vi.fn()
const mockUpdate = vi.fn()
const mockDelete = vi.fn()
const mockOrderFindFirst = vi.fn()

vi.mock('@/lib/prisma', () => ({
  prisma: {
    table: {
      findMany: (...args: unknown[]) => mockFindMany(...args),
      findFirst: (...args: unknown[]) => mockFindFirst(...args),
      create: (...args: unknown[]) => mockCreate(...args),
      findUnique: (...args: unknown[]) => mockFindUnique(...args),
      update: (...args: unknown[]) => mockUpdate(...args),
      delete: (...args: unknown[]) => mockDelete(...args),
    },
    order: {
      findFirst: (...args: unknown[]) => mockOrderFindFirst(...args),
    },
  },
}))

// ─── Import route handlers ───────────────────────────────────────────
import { GET, POST } from '../route'
import { GET as GET_ONE, PUT, DELETE } from '../[id]/route'

// ─── Helpers ────────────────────────────────────────────────────────

function makeRequest(url: string, method: string, body?: Record<string, unknown>): Request {
  const init: RequestInit = { method, headers: { 'content-type': 'application/json' } }
  if (body) init.body = JSON.stringify(body)
  return new Request(url, init)
}

function makeContext(id: string | number) {
  return { params: Promise.resolve({ id: String(id) }) }
}

async function json(res: Response) {
  return res.json()
}

// ─── Reset mocks ────────────────────────────────────────────────────
beforeEach(() => {
  vi.clearAllMocks()
})

// =====================================================================
// GET /api/admin/tables
// =====================================================================
describe('GET /api/admin/tables', () => {
  it('returns empty list when no tables exist', async () => {
    mockFindMany.mockResolvedValue([])

    const res = await GET()
    expect(res.status).toBe(200)

    const data = await json(res)
    expect(data.tables).toHaveLength(0)
  })

  it('returns tables ordered by number with orderCount', async () => {
    mockFindMany.mockResolvedValue([
      { id: 1, number: 1, name: 'Bàn 1', orders: [{ id: 10 }, { id: 11 }] },
      { id: 2, number: 2, name: 'Bàn 2', orders: [] },
    ])

    const res = await GET()
    expect(res.status).toBe(200)

    const data = await json(res)
    expect(data.tables).toHaveLength(2)
    expect(data.tables[0]).toEqual({ id: 1, number: 1, name: 'Bàn 1', orderCount: 2 })
    expect(data.tables[1]).toEqual({ id: 2, number: 2, name: 'Bàn 2', orderCount: 0 })
  })

  it('returns 500 on database error', async () => {
    mockFindMany.mockRejectedValue(new Error('DB error'))

    const res = await GET()
    expect(res.status).toBe(500)
  })
})

// =====================================================================
// POST /api/admin/tables
// =====================================================================
describe('POST /api/admin/tables', () => {
  it('creates first table with number=1, name="Bàn 1"', async () => {
    mockFindFirst.mockResolvedValue(null) // no existing tables
    mockCreate.mockResolvedValue({ id: 1, number: 1, name: 'Bàn 1' })

    const req = makeRequest('http://localhost/api/admin/tables', 'POST')
    const res = await POST(req as any)
    expect(res.status).toBe(201)

    const data = await json(res)
    expect(data.number).toBe(1)
    expect(data.name).toBe('Bàn 1')
    expect(data.orderCount).toBe(0)
  })

  it('auto-numbers to max+1', async () => {
    mockFindFirst.mockResolvedValue({ number: 5 })
    mockCreate.mockResolvedValue({ id: 3, number: 6, name: 'Bàn 6' })

    const req = makeRequest('http://localhost/api/admin/tables', 'POST')
    const res = await POST(req as any)
    expect(res.status).toBe(201)

    const data = await json(res)
    expect(data.number).toBe(6)
    expect(data.name).toBe('Bàn 6')
  })

  it('returns 500 on database error', async () => {
    mockFindFirst.mockRejectedValue(new Error('DB error'))

    const req = makeRequest('http://localhost/api/admin/tables', 'POST')
    const res = await POST(req as any)
    expect(res.status).toBe(500)
  })
})

// =====================================================================
// GET /api/admin/tables/[id]
// =====================================================================
describe('GET /api/admin/tables/[id]', () => {
  it('returns single table with orderCount', async () => {
    mockFindUnique.mockResolvedValue({
      id: 1,
      number: 1,
      name: 'Bàn 1',
      orders: [{ id: 10 }, { id: 11 }, { id: 12 }],
    })

    const req = makeRequest('http://localhost/api/admin/tables/1', 'GET')
    const res = await GET_ONE(req as any, makeContext(1))
    expect(res.status).toBe(200)

    const data = await json(res)
    expect(data).toEqual({ id: 1, number: 1, name: 'Bàn 1', orderCount: 3 })
  })

  it('returns 404 for non-existent table', async () => {
    mockFindUnique.mockResolvedValue(null)

    const req = makeRequest('http://localhost/api/admin/tables/999', 'GET')
    const res = await GET_ONE(req as any, makeContext(999))
    expect(res.status).toBe(404)
  })

  it('returns 400 for invalid ID (NaN)', async () => {
    const req = makeRequest('http://localhost/api/admin/tables/abc', 'GET')
    const res = await GET_ONE(req as any, makeContext('abc'))
    expect(res.status).toBe(400)
  })
})

// =====================================================================
// PUT /api/admin/tables/[id]
// =====================================================================
describe('PUT /api/admin/tables/[id]', () => {
  it('renames table with valid name', async () => {
    mockFindUnique.mockResolvedValue({ id: 1, number: 1, name: 'Bàn 1', orders: [] })
    mockUpdate.mockResolvedValue({ id: 1, number: 1, name: 'Bàn VIP' })

    const req = makeRequest('http://localhost/api/admin/tables/1', 'PUT', { name: 'Bàn VIP' })
    const res = await PUT(req as any, makeContext(1))
    expect(res.status).toBe(200)

    const data = await json(res)
    expect(data.name).toBe('Bàn VIP')
  })

  it('trims whitespace from name', async () => {
    mockFindUnique.mockResolvedValue({ id: 1, number: 1, name: 'Bàn 1', orders: [] })
    mockUpdate.mockResolvedValue({ id: 1, number: 1, name: 'Bàn sân vườn' })

    const req = makeRequest('http://localhost/api/admin/tables/1', 'PUT', { name: '  Bàn sân vườn  ' })
    await PUT(req as any, makeContext(1))

    const updateArg = mockUpdate.mock.calls[0][0]
    expect(updateArg.data.name).toBe('Bàn sân vườn')
  })

  it('returns 400 for empty name', async () => {
    const req = makeRequest('http://localhost/api/admin/tables/1', 'PUT', { name: '' })
    const res = await PUT(req as any, makeContext(1))
    expect(res.status).toBe(400)
  })

  it('returns 400 for whitespace-only name', async () => {
    const req = makeRequest('http://localhost/api/admin/tables/1', 'PUT', { name: '   ' })
    const res = await PUT(req as any, makeContext(1))
    expect(res.status).toBe(400)
  })

  it('returns 400 for name longer than 50 characters', async () => {
    const req = makeRequest('http://localhost/api/admin/tables/1', 'PUT', {
      name: 'B'.repeat(51),
    })
    const res = await PUT(req as any, makeContext(1))
    expect(res.status).toBe(400)
  })

  it('returns 404 for non-existent table', async () => {
    mockFindUnique.mockResolvedValue(null)

    const req = makeRequest('http://localhost/api/admin/tables/999', 'PUT', { name: 'New Name' })
    const res = await PUT(req as any, makeContext(999))
    expect(res.status).toBe(404)
  })

  it('returns 400 for invalid ID', async () => {
    const req = makeRequest('http://localhost/api/admin/tables/abc', 'PUT', { name: 'New' })
    const res = await PUT(req as any, makeContext('abc'))
    expect(res.status).toBe(400)
  })
})

// =====================================================================
// DELETE /api/admin/tables/[id]
// =====================================================================
describe('DELETE /api/admin/tables/[id]', () => {
  it('deletes table when no unpaid orders exist', async () => {
    mockFindUnique.mockResolvedValue({ id: 2, number: 2, name: 'Bàn 2' })
    mockOrderFindFirst.mockResolvedValue(null) // no unpaid orders
    mockDelete.mockResolvedValue({ id: 2, number: 2, name: 'Bàn 2' })

    const req = makeRequest('http://localhost/api/admin/tables/2', 'DELETE')
    const res = await DELETE(req as any, makeContext(2))
    expect(res.status).toBe(204)
    expect(mockDelete).toHaveBeenCalledWith({ where: { id: 2 } })
  })

  it('returns 409 when unpaid orders exist (guard triggered)', async () => {
    mockFindUnique.mockResolvedValue({ id: 3, number: 3, name: 'Bàn 3' })
    mockOrderFindFirst.mockResolvedValue({ id: 100, status: 'PENDING' })

    const req = makeRequest('http://localhost/api/admin/tables/3', 'DELETE')
    const res = await DELETE(req as any, makeContext(3))
    expect(res.status).toBe(409)

    const data = await json(res)
    expect(data.error).toContain('chưa thanh toán')
    expect(mockDelete).not.toHaveBeenCalled()
  })

  it('returns 409 when table has PAID orders only (no unpaid) → should succeed', async () => {
    // PAID orders are excluded from the unpaid check, so delete should succeed
    mockFindUnique.mockResolvedValue({ id: 4, number: 4, name: 'Bàn 4' })
    mockOrderFindFirst.mockResolvedValue(null) // no unpaid orders found
    mockDelete.mockResolvedValue({ id: 4, number: 4, name: 'Bàn 4' })

    const req = makeRequest('http://localhost/api/admin/tables/4', 'DELETE')
    const res = await DELETE(req as any, makeContext(4))
    expect(res.status).toBe(204)
  })

  it('returns 404 for non-existent table', async () => {
    mockFindUnique.mockResolvedValue(null)

    const req = makeRequest('http://localhost/api/admin/tables/999', 'DELETE')
    const res = await DELETE(req as any, makeContext(999))
    expect(res.status).toBe(404)
  })

  it('returns 400 for invalid ID', async () => {
    const req = makeRequest('http://localhost/api/admin/tables/abc', 'DELETE')
    const res = await DELETE(req as any, makeContext('abc'))
    expect(res.status).toBe(400)
  })
})

// ─── Import prisma mock for the guard test ───────────────────────────
import { prisma } from '@/lib/prisma'

'use client'

import { useState, useEffect, useCallback, useRef } from 'react'

// ─── Types ──────────────────────────────────────────────────────────

export interface MenuItemData {
  id?: number
  name: string
  price: number
  category: 'DRINK' | 'FOOD'
  description: string | null
  sortOrder: number
}

interface MenuItemFormProps {
  isOpen: boolean
  onClose: () => void
  onSuccess: () => void
  editItem?: MenuItemData | null
}

// ─── MenuItemForm ───────────────────────────────────────────────────

export default function MenuItemForm({
  isOpen,
  onClose,
  onSuccess,
  editItem,
}: MenuItemFormProps) {
  const isEdit = !!editItem?.id

  // ─── Form state ───────────────────────────────────────────────
  const [name, setName] = useState('')
  const [price, setPrice] = useState('')
  const [category, setCategory] = useState<'DRINK' | 'FOOD'>('DRINK')
  const [description, setDescription] = useState('')
  const [sortOrder, setSortOrder] = useState('0')

  // ─── Validation errors ────────────────────────────────────────
  const [nameError, setNameError] = useState<string | null>(null)
  const [priceError, setPriceError] = useState<string | null>(null)

  // ─── Submit state ─────────────────────────────────────────────
  const [submitting, setSubmitting] = useState(false)
  const [submitError, setSubmitError] = useState<string | null>(null)

  // ─── Animation state ──────────────────────────────────────────
  const [visible, setVisible] = useState(false)
  const overlayRef = useRef<HTMLDivElement>(null)
  const nameRef = useRef<HTMLInputElement>(null)

  // ─── Populate form when editing ───────────────────────────────
  useEffect(() => {
    if (isOpen) {
      if (editItem) {
        setName(editItem.name)
        setPrice(String(editItem.price))
        setCategory(editItem.category)
        setDescription(editItem.description ?? '')
        setSortOrder(String(editItem.sortOrder))
      } else {
        setName('')
        setPrice('')
        setCategory('DRINK')
        setDescription('')
        setSortOrder('0')
      }
      setNameError(null)
      setPriceError(null)
      setSubmitError(null)
      requestAnimationFrame(() => {
        setVisible(true)
        // Focus name field after animation starts
        setTimeout(() => nameRef.current?.focus(), 300)
      })
    }
  }, [isOpen, editItem])

  // ─── Close with exit animation ────────────────────────────────
  const handleClose = useCallback(() => {
    setVisible(false)
    setTimeout(() => onClose(), 200)
  }, [onClose])

  // ─── Click outside → dismiss ──────────────────────────────────
  const handleOverlayClick = useCallback(
    (e: React.MouseEvent) => {
      if (e.target === overlayRef.current) handleClose()
    },
    [handleClose],
  )

  // ─── Validate ─────────────────────────────────────────────────
  const validate = useCallback((): boolean => {
    let valid = true

    if (!name.trim()) {
      setNameError('Tên món không được để trống')
      valid = false
    } else {
      setNameError(null)
    }

    const priceNum = parseInt(price, 10)
    if (!price || isNaN(priceNum) || priceNum <= 0) {
      setPriceError('Giá phải lớn hơn 0')
      valid = false
    } else {
      setPriceError(null)
    }

    return valid
  }, [name, price])

  // ─── Submit ───────────────────────────────────────────────────
  const handleSubmit = useCallback(async () => {
    if (!validate()) return

    setSubmitting(true)
    setSubmitError(null)

    const payload = {
      name: name.trim(),
      price: parseInt(price, 10),
      category,
      description: description.trim() || null,
      sortOrder: parseInt(sortOrder, 10) || 0,
    }

    try {
      const url = isEdit
        ? `/api/admin/menu/${editItem!.id}`
        : '/api/admin/menu'
      const method = isEdit ? 'PUT' : 'POST'

      const res = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      })

      if (!res.ok) {
        const data = await res.json().catch(() => ({}))
        setSubmitError(data.error ?? `Lỗi ${isEdit ? 'cập nhật' : 'tạo'} món (${res.status})`)
        return
      }

      const data = await res.json()
      console.log(
        `[MenuItemForm] ${isEdit ? 'Updated' : 'Created'} menu item: ${data.item?.name}`,
      )
      onSuccess()
      handleClose()
    } catch (err) {
      console.error('[MenuItemForm] Submit error:', err)
      setSubmitError('Lỗi kết nối. Vui lòng thử lại.')
    } finally {
      setSubmitting(false)
    }
  }, [validate, name, price, category, description, sortOrder, isEdit, editItem, onSuccess, handleClose])

  // ─── Don't render if not open ─────────────────────────────────
  if (!isOpen) return null

  return (
    /* ─── Overlay ──────────────────────────────────────────── */
    <div
      ref={overlayRef}
      onClick={handleOverlayClick}
      className={`
        fixed inset-0 z-50 flex items-end justify-center
        transition-colors duration-200
        ${visible ? 'bg-black/40' : 'bg-black/0'}
      `}
      style={{ transitionProperty: 'background-color' }}
    >
      {/* ─── Modal (slide up from bottom) ───────────────────── */}
      <div
        className={`
          w-full max-w-lg bg-amber-50 rounded-t-3xl
          overflow-hidden flex flex-col
          ${visible ? 'translate-y-0' : 'translate-y-full'}
        `}
        style={{
          maxHeight: '90vh',
          transitionProperty: 'transform',
          transitionTimingFunction: visible
            ? 'cubic-bezier(0.16, 1, 0.3, 1)'
            : 'cubic-bezier(0.4, 0, 1, 1)',
          transitionDuration: visible ? '300ms' : '200ms',
        }}
      >
        {/* ─── Drag handle + Header ──────────────────────────── */}
        <div className="sticky top-0 z-10 bg-amber-50">
          <div className="flex justify-center pt-3 pb-1">
            <div className="w-10 h-1 rounded-full bg-amber-300/60" />
          </div>
          <div className="flex items-center justify-between px-5 pb-3">
            <h2
              className="text-lg font-bold text-amber-900"
              style={{ textWrap: 'balance' }}
            >
              {isEdit ? 'Sửa món' : 'Thêm món mới'}
            </h2>
            <button
              onClick={handleClose}
              className="min-h-[44px] min-w-[44px] flex items-center justify-center rounded-xl text-amber-600 hover:text-amber-900 hover:bg-amber-100 transition-colors active:scale-[0.96]"
              style={{ transitionProperty: 'background-color, color, transform' }}
              aria-label="Đóng"
            >
              <svg
                xmlns="http://www.w3.org/2000/svg"
                fill="none"
                viewBox="0 0 24 24"
                strokeWidth={2.5}
                stroke="currentColor"
                className="w-5 h-5"
              >
                <path strokeLinecap="round" strokeLinejoin="round" d="M6 18 18 6M6 6l12 12" />
              </svg>
            </button>
          </div>
          <div className="h-px bg-amber-200/50" />
        </div>

        {/* ─── Scrollable form body ──────────────────────────── */}
        <div
          className="flex-1 overflow-y-auto px-5 py-5"
          style={{ WebkitOverflowScrolling: 'touch' }}
        >
          {/* Name */}
          <div className="mb-4">
            <label
              htmlFor="menu-name"
              className="block text-sm font-semibold text-amber-800 mb-1.5"
            >
              Tên món <span className="text-red-500">*</span>
            </label>
            <input
              ref={nameRef}
              id="menu-name"
              type="text"
              value={name}
              onChange={(e) => {
                setName(e.target.value)
                if (nameError) setNameError(null)
              }}
              placeholder="VD: Trà sữa trân châu"
              className={`
                w-full rounded-xl border bg-white px-4 py-3 text-sm text-amber-900
                placeholder:text-amber-400
                focus:outline-none focus:ring-2 focus:ring-amber-600/30
                ${nameError ? 'border-red-400 ring-2 ring-red-200' : 'border-amber-200/60'}
              `}
              style={{ minHeight: 44 }}
            />
            {nameError && (
              <p className="mt-1.5 text-xs text-red-600 font-medium">{nameError}</p>
            )}
          </div>

          {/* Price */}
          <div className="mb-4">
            <label
              htmlFor="menu-price"
              className="block text-sm font-semibold text-amber-800 mb-1.5"
            >
              Giá (VNĐ) <span className="text-red-500">*</span>
            </label>
            <input
              id="menu-price"
              type="number"
              inputMode="numeric"
              value={price}
              onChange={(e) => {
                setPrice(e.target.value)
                if (priceError) setPriceError(null)
              }}
              placeholder="VD: 35000"
              className={`
                w-full rounded-xl border bg-white px-4 py-3 text-sm text-amber-900
                placeholder:text-amber-400
                focus:outline-none focus:ring-2 focus:ring-amber-600/30
                ${priceError ? 'border-red-400 ring-2 ring-red-200' : 'border-amber-200/60'}
              `}
              style={{ minHeight: 44, fontVariantNumeric: 'tabular-nums' }}
            />
            {priceError && (
              <p className="mt-1.5 text-xs text-red-600 font-medium">{priceError}</p>
            )}
          </div>

          {/* Category */}
          <div className="mb-4">
            <label className="block text-sm font-semibold text-amber-800 mb-1.5">
              Danh mục
            </label>
            <div className="inline-flex w-full rounded-xl bg-amber-100/70 p-1">
              {(['DRINK', 'FOOD'] as const).map((cat) => {
                const isActive = category === cat
                return (
                  <button
                    key={cat}
                    type="button"
                    onClick={() => setCategory(cat)}
                    className={`
                      flex-1 rounded-lg px-4 py-2.5 text-sm font-semibold
                      transition-colors duration-150 ease-out
                      ${
                        isActive
                          ? 'bg-amber-900 text-amber-50 shadow-sm shadow-amber-900/20'
                          : 'text-amber-700 hover:text-amber-900'
                      }
                    `}
                    style={{ minHeight: 44 }}
                  >
                    {cat === 'DRINK' ? 'Đồ uống' : 'Đồ ăn'}
                  </button>
                )
              })}
            </div>
          </div>

          {/* Description */}
          <div className="mb-4">
            <label
              htmlFor="menu-desc"
              className="block text-sm font-semibold text-amber-800 mb-1.5"
            >
              Mô tả{' '}
              <span className="text-amber-500 font-normal text-xs">(tuỳ chọn)</span>
            </label>
            <textarea
              id="menu-desc"
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              placeholder="Mô tả ngắn về món"
              rows={3}
              className="w-full rounded-xl border border-amber-200/60 bg-white px-4 py-3 text-sm text-amber-900 placeholder:text-amber-400 focus:outline-none focus:ring-2 focus:ring-amber-600/30 resize-none"
            />
          </div>

          {/* Sort Order */}
          <div className="mb-2">
            <label
              htmlFor="menu-sort"
              className="block text-sm font-semibold text-amber-800 mb-1.5"
            >
              Thứ tự{' '}
              <span className="text-amber-500 font-normal text-xs">(mặc định: 0)</span>
            </label>
            <input
              id="menu-sort"
              type="number"
              inputMode="numeric"
              value={sortOrder}
              onChange={(e) => setSortOrder(e.target.value)}
              className="w-full rounded-xl border border-amber-200/60 bg-white px-4 py-3 text-sm text-amber-900 placeholder:text-amber-400 focus:outline-none focus:ring-2 focus:ring-amber-600/30"
              style={{ minHeight: 44, fontVariantNumeric: 'tabular-nums' }}
            />
          </div>
        </div>

        {/* ─── Footer: error + action buttons ────────────────── */}
        <div className="border-t border-amber-200/60 bg-gradient-to-r from-amber-50 to-orange-50 px-5 py-4">
          {submitError && (
            <p className="text-sm text-red-600 mb-3 bg-red-50 rounded-lg px-3 py-2">
              {submitError}
            </p>
          )}

          <div className="flex gap-3">
            <button
              type="button"
              onClick={handleClose}
              disabled={submitting}
              className="flex-1 min-h-[48px] rounded-2xl bg-white border border-amber-200/60 text-amber-700 font-semibold text-sm hover:bg-amber-100 transition-colors active:scale-[0.96] disabled:opacity-50"
              style={{ transitionProperty: 'background-color, transform' }}
            >
              Huỷ
            </button>
            <button
              type="button"
              onClick={handleSubmit}
              disabled={submitting}
              className="flex-[2] min-h-[48px] rounded-2xl bg-amber-700 text-amber-50 font-bold text-sm hover:bg-amber-800 shadow-md shadow-amber-900/20 transition-colors active:scale-[0.96] disabled:opacity-50 disabled:cursor-not-allowed"
              style={{ transitionProperty: 'background-color, transform, box-shadow' }}
            >
              {submitting ? (
                <span className="inline-flex items-center gap-2">
                  <span className="inline-block w-4 h-4 border-2 border-current border-t-transparent rounded-full animate-spin" />
                  {isEdit ? 'Đang lưu…' : 'Đang tạo…'}
                </span>
              ) : isEdit ? (
                'Lưu thay đổi'
              ) : (
                'Tạo món mới'
              )}
            </button>
          </div>
        </div>
      </div>
    </div>
  )
}

'use client'

import { useState, useEffect, useCallback, useRef } from 'react'
import { formatVND } from '@/lib/format'
import { useToast } from '@/components/ui/ToastProvider'
import MenuItemForm, { type MenuItemData } from '@/components/admin/MenuItemForm'

// ─── Types ──────────────────────────────────────────────────────────

interface MenuItem {
  id: number
  name: string
  price: number
  category: 'DRINK' | 'FOOD'
  description: string | null
  available: boolean
  hidden: boolean
  sortOrder: number
}

type Tab = 'DRINK' | 'FOOD'

const TABS: { key: Tab; label: string; emoji: string }[] = [
  { key: 'DRINK', label: 'Đồ uống', emoji: '🧋' },
  { key: 'FOOD', label: 'Đồ ăn', emoji: '🍜' },
]

// ─── Admin Menu Page ────────────────────────────────────────────────

export default function AdminMenuPage() {
  const toast = useToast()

  // ─── Data state ─────────────────────────────────────────────
  const [items, setItems] = useState<MenuItem[]>([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)
  const [activeTab, setActiveTab] = useState<Tab>('DRINK')

  // ─── Form modal state ───────────────────────────────────────
  const [showForm, setShowForm] = useState(false)
  const [editItem, setEditItem] = useState<MenuItemData | null>(null)

  // ─── Fetch menu items ───────────────────────────────────────
  const fetchItems = useCallback(async () => {
    try {
      const res = await fetch('/api/admin/menu')
      if (!res.ok) throw new Error(`Lỗi tải thực đơn (${res.status})`)
      const data = await res.json()
      setItems(data.items ?? [])
      setError(null)
      console.log(`[AdminMenu] Loaded ${data.items?.length ?? 0} menu items`)
    } catch (err) {
      const msg = err instanceof Error ? err.message : 'Lỗi không xác định'
      setError(msg)
      console.error('[AdminMenu] Fetch error:', err)
    } finally {
      setLoading(false)
    }
  }, [])

  useEffect(() => {
    fetchItems()
  }, [fetchItems])

  // ─── Toggle availability ────────────────────────────────────
  const handleToggleAvailable = useCallback(
    async (item: MenuItem) => {
      const newValue = !item.available
      try {
        const res = await fetch(`/api/admin/menu/${item.id}`, {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ field: 'available', value: newValue }),
        })
        if (!res.ok) {
          const data = await res.json().catch(() => ({}))
          toast.error(data.error ?? 'Không thể cập nhật trạng thái')
          return
        }
        toast.success(
          newValue
            ? `"${item.name}" đã chuyển về Còn hàng`
            : `"${item.name}" đã chuyển sang Hết hàng`,
        )
        console.log(`[AdminMenu] Toggled available=${newValue} for: ${item.name}`)
        fetchItems()
      } catch {
        toast.error('Lỗi kết nối. Vui lòng thử lại.')
      }
    },
    [fetchItems, toast],
  )

  // ─── Soft-delete (hide) ─────────────────────────────────────
  const handleDelete = useCallback(
    async (item: MenuItem) => {
      try {
        const res = await fetch(`/api/admin/menu/${item.id}`, {
          method: 'DELETE',
        })
        if (!res.ok) {
          const data = await res.json().catch(() => ({}))
          toast.error(data.error ?? 'Không thể xoá món')
          return
        }
        toast.success(`Đã ẩn "${item.name}"`)
        console.log(`[AdminMenu] Soft-deleted: ${item.name}`)
        fetchItems()
      } catch {
        toast.error('Lỗi kết nối. Vui lòng thử lại.')
      }
    },
    [fetchItems, toast],
  )

  // ─── Restore (unhide) ──────────────────────────────────────
  const handleRestore = useCallback(
    async (item: MenuItem) => {
      try {
        const res = await fetch(`/api/admin/menu/${item.id}`, {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ field: 'hidden', value: false }),
        })
        if (!res.ok) {
          const data = await res.json().catch(() => ({}))
          toast.error(data.error ?? 'Không thể khôi phục món')
          return
        }
        toast.success(`Đã khôi phục "${item.name}"`)
        console.log(`[AdminMenu] Restored: ${item.name}`)
        fetchItems()
      } catch {
        toast.error('Lỗi kết nối. Vui lòng thử lại.')
      }
    },
    [fetchItems, toast],
  )

  // ─── Open create form ───────────────────────────────────────
  const handleCreate = useCallback(() => {
    setEditItem(null)
    setShowForm(true)
  }, [])

  // ─── Open edit form ─────────────────────────────────────────
  const handleEdit = useCallback((item: MenuItem) => {
    setEditItem({
      id: item.id,
      name: item.name,
      price: item.price,
      category: item.category,
      description: item.description,
      sortOrder: item.sortOrder,
    })
    setShowForm(true)
  }, [])

  // ─── Form success callback ─────────────────────────────────
  const handleFormSuccess = useCallback(() => {
    toast.success(editItem ? 'Đã cập nhật món' : 'Đã tạo món mới')
    fetchItems()
  }, [editItem, fetchItems, toast])

  // ─── Filter items for active tab ────────────────────────────
  const filtered = items
    .filter((item) => item.category === activeTab)
    .sort((a, b) => {
      // Hidden items go to bottom
      if (a.hidden !== b.hidden) return a.hidden ? 1 : -1
      return a.sortOrder - b.sortOrder
    })

  // ─── Loading state ──────────────────────────────────────────
  if (loading) {
    return (
      <div className="flex items-center justify-center py-24">
        <span className="inline-block w-8 h-8 border-3 border-amber-300 border-t-amber-700 rounded-full animate-spin" />
      </div>
    )
  }

  // ─── Error state ────────────────────────────────────────────
  if (error) {
    return (
      <div className="flex flex-col items-center justify-center py-24 text-center px-4">
        <span className="text-4xl mb-3 opacity-50">⚠️</span>
        <p className="text-amber-800 font-medium mb-4">{error}</p>
        <button
          onClick={() => {
            setLoading(true)
            setError(null)
            fetchItems()
          }}
          className="min-h-[44px] px-6 py-2 rounded-xl bg-amber-700 text-amber-50 font-semibold text-sm hover:bg-amber-800 transition-colors active:scale-[0.96]"
          style={{ transitionProperty: 'background-color, transform' }}
        >
          Thử lại
        </button>
      </div>
    )
  }

  return (
    <>
      {/* ── Header ─────────────────────────────────────────────── */}
      <header className="sticky top-0 z-10 bg-amber-50/95 backdrop-blur-sm">
        <div className="flex items-center justify-between gap-3 px-4 py-3">
          <h1
            className="text-lg font-bold text-amber-950 tracking-tight"
            style={{ textWrap: 'balance' }}
          >
            📋 Quản lý thực đơn
          </h1>
          <button
            onClick={handleCreate}
            className="min-h-[44px] inline-flex items-center gap-1.5 rounded-xl bg-amber-800 px-4 py-2 text-sm font-semibold text-amber-50 shadow-sm shadow-amber-900/20 hover:bg-amber-900 transition-colors active:scale-[0.96]"
            style={{ transitionProperty: 'background-color, transform' }}
          >
            <svg
              xmlns="http://www.w3.org/2000/svg"
              fill="none"
              viewBox="0 0 24 24"
              strokeWidth={2.5}
              stroke="currentColor"
              className="w-4 h-4"
            >
              <path strokeLinecap="round" strokeLinejoin="round" d="M12 4.5v15m7.5-7.5h-15" />
            </svg>
            Thêm
          </button>
        </div>

        {/* ── Tab Bar ──────────────────────────────────────────── */}
        <div className="px-4 pb-3">
          <nav
            role="tablist"
            aria-label="Danh mục thực đơn"
            className="inline-flex w-full rounded-xl bg-amber-100/70 p-1"
          >
            {TABS.map((tab) => {
              const isActive = activeTab === tab.key
              const count = items.filter(
                (i) => i.category === tab.key && !i.hidden,
              ).length
              return (
                <button
                  key={tab.key}
                  role="tab"
                  aria-selected={isActive}
                  aria-controls={`panel-${tab.key}`}
                  onClick={() => setActiveTab(tab.key)}
                  className={`
                    flex-1 rounded-lg px-4 py-2.5 text-sm font-semibold
                    transition-colors transition-shadow duration-150 ease-out
                    ${
                      isActive
                        ? 'bg-amber-900 text-amber-50 shadow-sm shadow-amber-900/20'
                        : 'text-amber-700 hover:text-amber-900'
                    }
                  `}
                  style={{ minHeight: 44 }}
                >
                  {tab.label}{' '}
                  <span
                    className={`text-xs ${isActive ? 'text-amber-200' : 'text-amber-500'}`}
                  >
                    ({count})
                  </span>
                </button>
              )
            })}
          </nav>
        </div>

        <div className="h-px bg-amber-200/50" />
      </header>

      {/* ── Item List ──────────────────────────────────────────── */}
      <main
        id={`panel-${activeTab}`}
        role="tabpanel"
        aria-label={TABS.find((t) => t.key === activeTab)?.label}
        className="px-4 pb-28 pt-4"
      >
        <div className="flex flex-col gap-3">
          {filtered.map((item, index) => (
            <AdminItemCard
              key={item.id}
              item={item}
              index={index}
              onEdit={handleEdit}
              onToggleAvailable={handleToggleAvailable}
              onDelete={handleDelete}
              onRestore={handleRestore}
            />
          ))}
        </div>

        {filtered.length === 0 && (
          <div className="flex flex-col items-center justify-center py-16 text-center">
            <span className="text-4xl mb-3 opacity-40">
              {activeTab === 'DRINK' ? '🧋' : '🍜'}
            </span>
            <p
              className="text-sm text-amber-700/60"
              style={{ textWrap: 'pretty' }}
            >
              Chưa có món nào trong danh mục này.
            </p>
            <button
              onClick={handleCreate}
              className="mt-4 min-h-[44px] inline-flex items-center gap-1.5 rounded-xl bg-amber-100 px-5 py-2 text-sm font-semibold text-amber-800 hover:bg-amber-200 transition-colors active:scale-[0.96]"
              style={{ transitionProperty: 'background-color, transform' }}
            >
              Thêm món đầu tiên
            </button>
          </div>
        )}
      </main>

      {/* ── Create/Edit Form Modal ─────────────────────────────── */}
      <MenuItemForm
        isOpen={showForm}
        onClose={() => setShowForm(false)}
        onSuccess={handleFormSuccess}
        editItem={editItem}
      />
    </>
  )
}

// ─── Admin Item Card ────────────────────────────────────────────────

function AdminItemCard({
  item,
  index,
  onEdit,
  onToggleAvailable,
  onDelete,
  onRestore,
}: {
  item: MenuItem
  index: number
  onEdit: (item: MenuItem) => void
  onToggleAvailable: (item: MenuItem) => void
  onDelete: (item: MenuItem) => void
  onRestore: (item: MenuItem) => void
}) {
  const [confirmingDelete, setConfirmingDelete] = useState(false)
  const deleteTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null)

  // Auto-reset delete confirmation after 3s
  useEffect(() => {
    if (confirmingDelete) {
      deleteTimerRef.current = setTimeout(() => setConfirmingDelete(false), 3000)
    }
    return () => {
      if (deleteTimerRef.current) {
        clearTimeout(deleteTimerRef.current)
        deleteTimerRef.current = null
      }
    }
  }, [confirmingDelete])

  const handleDeleteTap = useCallback(() => {
    if (!confirmingDelete) {
      setConfirmingDelete(true)
      return
    }
    // Second tap — execute
    setConfirmingDelete(false)
    onDelete(item)
  }, [confirmingDelete, item, onDelete])

  const isHidden = item.hidden
  const isUnavailable = !item.available

  return (
    <div
      className={`
        rounded-2xl bg-white p-4
        transition-all duration-150 ease-out
        ${isHidden ? 'opacity-55 ring-1 ring-amber-200/60' : ''}
      `}
      style={{
        boxShadow: isHidden
          ? '0 1px 2px rgba(120, 53, 15, 0.04)'
          : '0 1px 3px rgba(120, 53, 15, 0.06), 0 4px 12px rgba(120, 53, 15, 0.04)',
        animationDelay: `${index * 50}ms`,
        animation: 'adminCardEnter 0.3s ease-out both',
      }}
    >
      {/* ─── Top row: name + badges ──────────────────────────── */}
      <div className="flex items-start justify-between gap-3 mb-2">
        <div className="min-w-0 flex-1">
          <h3
            className={`text-[15px] font-semibold leading-snug ${
              isHidden ? 'text-amber-800/60' : 'text-amber-950'
            }`}
            style={{ textWrap: 'balance' }}
          >
            {item.name}
          </h3>
          {item.description && (
            <p
              className={`mt-0.5 text-sm leading-relaxed ${
                isHidden ? 'text-amber-700/40' : 'text-amber-700/65'
              }`}
              style={{ textWrap: 'pretty' }}
            >
              {item.description}
            </p>
          )}
        </div>

        {/* Badges column */}
        <div className="flex flex-col items-end gap-1.5 flex-shrink-0">
          {isHidden && (
            <span className="inline-flex items-center rounded-lg bg-slate-100 px-2.5 py-1 text-xs font-medium text-slate-600">
              Đã ẩn
            </span>
          )}
          {isUnavailable && !isHidden && (
            <span className="inline-flex items-center rounded-lg bg-amber-100/80 px-2.5 py-1 text-xs font-medium text-amber-700/70">
              Hết hàng
            </span>
          )}
        </div>
      </div>

      {/* ─── Price + sort order ──────────────────────────────── */}
      <div className="flex items-center gap-3 mb-3">
        <span
          className={`text-sm font-semibold ${
            isHidden ? 'text-amber-700/50' : 'text-amber-800'
          }`}
          style={{ fontVariantNumeric: 'tabular-nums' }}
        >
          {formatVND(item.price)}
        </span>
        {item.sortOrder !== 0 && (
          <span className="text-xs text-amber-500/70">
            #{item.sortOrder}
          </span>
        )}
      </div>

      {/* ─── Action buttons ──────────────────────────────────── */}
      <div className="flex items-center gap-2 flex-wrap">
        {isHidden ? (
          /* Restore button for hidden items */
          <button
            onClick={() => onRestore(item)}
            className="min-h-[40px] inline-flex items-center gap-1.5 rounded-xl bg-emerald-50 px-3.5 py-2 text-xs font-semibold text-emerald-700 ring-1 ring-inset ring-emerald-200 hover:bg-emerald-100 transition-colors active:scale-[0.96]"
            style={{ transitionProperty: 'background-color, transform' }}
          >
            <svg
              xmlns="http://www.w3.org/2000/svg"
              fill="none"
              viewBox="0 0 24 24"
              strokeWidth={2}
              stroke="currentColor"
              className="w-3.5 h-3.5"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                d="M9 15 3 9m0 0 6-6M3 9h12a6 6 0 0 1 0 12h-3"
              />
            </svg>
            Khôi phục
          </button>
        ) : (
          <>
            {/* Edit */}
            <button
              onClick={() => onEdit(item)}
              className="min-h-[40px] inline-flex items-center gap-1.5 rounded-xl bg-amber-50 px-3.5 py-2 text-xs font-semibold text-amber-800 ring-1 ring-inset ring-amber-200/60 hover:bg-amber-100 transition-colors active:scale-[0.96]"
              style={{ transitionProperty: 'background-color, transform' }}
            >
              <svg
                xmlns="http://www.w3.org/2000/svg"
                fill="none"
                viewBox="0 0 24 24"
                strokeWidth={2}
                stroke="currentColor"
                className="w-3.5 h-3.5"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  d="m16.862 4.487 1.687-1.688a1.875 1.875 0 1 1 2.652 2.652L10.582 16.07a4.5 4.5 0 0 1-1.897 1.13L6 18l.8-2.685a4.5 4.5 0 0 1 1.13-1.897l8.932-8.931Zm0 0L19.5 7.125"
                />
              </svg>
              Sửa
            </button>

            {/* Toggle availability */}
            <button
              onClick={() => onToggleAvailable(item)}
              className={`
                min-h-[40px] inline-flex items-center gap-1.5 rounded-xl px-3.5 py-2 text-xs font-semibold ring-1 ring-inset
                transition-colors active:scale-[0.96]
                ${
                  item.available
                    ? 'bg-orange-50 text-orange-700 ring-orange-200 hover:bg-orange-100'
                    : 'bg-emerald-50 text-emerald-700 ring-emerald-200 hover:bg-emerald-100'
                }
              `}
              style={{ transitionProperty: 'background-color, transform' }}
            >
              {item.available ? (
                <>
                  <svg
                    xmlns="http://www.w3.org/2000/svg"
                    fill="none"
                    viewBox="0 0 24 24"
                    strokeWidth={2}
                    stroke="currentColor"
                    className="w-3.5 h-3.5"
                  >
                    <path
                      strokeLinecap="round"
                      strokeLinejoin="round"
                      d="M18.364 18.364A9 9 0 0 0 5.636 5.636m12.728 12.728A9 9 0 0 1 5.636 5.636m12.728 12.728L5.636 5.636"
                    />
                  </svg>
                  Hết hàng
                </>
              ) : (
                <>
                  <svg
                    xmlns="http://www.w3.org/2000/svg"
                    fill="none"
                    viewBox="0 0 24 24"
                    strokeWidth={2}
                    stroke="currentColor"
                    className="w-3.5 h-3.5"
                  >
                    <path strokeLinecap="round" strokeLinejoin="round" d="m4.5 12.75 6 6 9-13.5" />
                  </svg>
                  Còn hàng
                </>
              )}
            </button>

            {/* Delete (two-tap) */}
            <button
              onClick={handleDeleteTap}
              className={`
                min-h-[40px] inline-flex items-center gap-1.5 rounded-xl px-3.5 py-2 text-xs font-semibold
                transition-all duration-150 active:scale-[0.96]
                ${
                  confirmingDelete
                    ? 'bg-red-600 text-white shadow-md shadow-red-900/20 ring-0'
                    : 'bg-red-50 text-red-600 ring-1 ring-inset ring-red-200 hover:bg-red-100'
                }
              `}
              style={{ transitionProperty: 'background-color, color, transform, box-shadow' }}
            >
              <svg
                xmlns="http://www.w3.org/2000/svg"
                fill="none"
                viewBox="0 0 24 24"
                strokeWidth={2}
                stroke="currentColor"
                className="w-3.5 h-3.5"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  d="m14.74 9-.346 9m-4.788 0L9.26 9m9.968-3.21c.342.052.682.107 1.022.166m-1.022-.165L18.16 19.673a2.25 2.25 0 0 1-2.244 2.077H8.084a2.25 2.25 0 0 1-2.244-2.077L4.772 5.79m14.456 0a48.108 48.108 0 0 0-3.478-.397m-12 .562c.34-.059.68-.114 1.022-.165m0 0a48.11 48.11 0 0 1 3.478-.397m7.5 0v-.916c0-1.18-.91-2.164-2.09-2.201a51.964 51.964 0 0 0-3.32 0c-1.18.037-2.09 1.022-2.09 2.201v.916m7.5 0a48.667 48.667 0 0 0-7.5 0"
                />
              </svg>
              {confirmingDelete ? 'Xác nhận xoá?' : 'Ẩn'}
            </button>
          </>
        )}
      </div>
    </div>
  )
}

